values.content:
=You are an expert SEO blog writer. Write a comprehensive, engaging blog post about:

Topic: {{ $json.body.topic }}
Target keyword: {{ $json.body.keyword }}
Tone: {{ $json.body.tone || 'professional but conversational' }}
Word count: {{ $json.body.wordCount || 1500 }}

Requirements:
1. Include the target keyword naturally 3-5 times
2. Use H2 and H3 headers for structure
3. Include a compelling introduction with a hook
4. Add bullet points or numbered lists where appropriate
5. End with a clear call-to-action
6. Write a meta description (155 chars max)
7. Suggest 5 related internal link anchors

Format as JSON:
{
  "title": "SEO-optimized title with keyword",
  "metaDescription": "155 char meta",
  "content": "Full blog post in markdown",
  "internalLinkAnchors": ["anchor1", "anchor2", ...]
}

parameters.jsCode:
const response = $input.first().json.message.content;

let parsed;
try {
  const jsonMatch = response.match(/```json\n?([\s\S]*?)\n?```/);
  const jsonStr = jsonMatch ? jsonMatch[1] : response;
  parsed = JSON.parse(jsonStr);
} catch (e) {
  // If JSON parsing fails, structure the raw content
  parsed = {
    title: 'Generated Blog Post',
    content: response,
    metaDescription: '',
    internalLinkAnchors: []
  };
}

// Calculate reading time
const wordCount = parsed.content.split(/\s+/).length;
const readingTime = Math.ceil(wordCount / 200);

return [{
  json: {
    ...parsed,
    wordCount,
    readingTime: `${readingTime} min read`,
    generatedAt: new Date().toISOString(),
    topic: $('Trigger').first().json.body.topic,
    keyword: $('Trigger').first().json.body.keyword
  }
}];
